__m128i SSE2_emulated_srlv_epi64(__m128i a, __m128i count)
{
 __m128i shift_low = _mm_srl_epi64(a, count); // high 64 is garbage
 __m128i count_high = _mm_unpackhi_epi64(count,count); // broadcast the high element
 __m128i shift_high = _mm_srl_epi64(a, count_high); // low 64 is garbage
 // SSE4.1:
 // return _mm_blend_epi16(shift_low, shift_high, 0x0F);

#if 1 // use movsd to blend
 __m128d blended = _mm_move_sd( _mm_castsi128_pd(shift_high), _mm_castsi128_pd(shift_low) ); // use movsd as a blend. Faster than multiple instructions on most CPUs, but probably bad on Nehalem. return _mm_castpd_si128(blended);
#else // SSE2 without using FP instructions:
 // if we're going to do it this way, we could have shuffled the input before shifting. Probably not helpful though. shift_high = _mm_unpackhi_epi64(shift_high, shift_high); // broadcast the high64
 return _mm_unpacklo_epi64(shift_high, shift_low); // combine
#endif
}

Other shuffles like pshufd or psrldq would work, but punpckhqdq gets the job done without needing an immediate byte, so it's one byte shorter. SSSE3 palignr could get the high element from one register and the low element from another register into one vector, but they'd be reversed (so we'd need a pshufd to swap high and low halves).

