Программа ниже сортирует строку на слова и числа. Максимальная длинна строки - 101 символ. Нужно чтобы при превышении этого кол-ва, программа не прекращала работу а выводила ошибку используя BUFMAX - аля printf ("Error");
#include <stdio.h> // printf, scanf, sscanf
#include <stdlib.h> // atoi

#define BUFMAX 101 //Max value of symbols

int isNumber (const char *buf) {

int i = 0;

while (buf[i] != '\0') {

 if ( buf[i] < '0' || buf[i] > '9' )
 {
 return 0;
 }
 else i++;
 }
return 1;
}

int main (void) {

char buf[101]; // Max length

while(scanf("%s", buf) != EOF) { // Scanning string until end of string. if (isNumber(buf)) // If found number - print. {
 printf ("number: %u", atoi(buf)) ;
 }
 else // If not all of above - just word. {
 printf ("word: %s",buf);
 }
 printf("\n");
 } // end of while
return 0;
} // end of main

A:

Смотрите. Вам нельзя допускать реального переполнения буфера, потому что это ведёт к неопределённому поведению программы.

