 curl_setopt($ch, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
 curl_setopt($ch, CURLOPT_USERPWD, "$account_sid:$token");
 $json = curl_exec($ch);
 if($json === false) {
 error_log("cURL error: ".curl_error($ch));
 error_log(print_r($json,true));
 }
 curl_close($ch);
 $obj = json_decode($json);

Any recommendations? A:

The following resources should help you find the results you're looking for. Your first code snippet above doesn't apply (Lookup is a different product).

